/**
 * Chicken Frat - Coffee Shop Minigame Engine
 * Vanilla JS + HTML5 Canvas 2D (No external assets, no build step)
 *
 * Originally generated by Gemini per GEMINI_PROMPT_coffee_shop.md, then patched
 * for multiplayer-safety before integration — see the "INTEGRATION PATCH NOTES"
 * comment block below for exactly what changed and why.
 *
 * ===================== INTEGRATION PATCH NOTES =====================
 * The delivered engine was excellent on the parts it was scoped to (POS/order
 * logic, scoring formula, rendering) but had a few gaps that only show up once
 * you actually run 2-3 independent copies of it in different browser tabs:
 *
 * 1. GRINDER JAM PROBABILITY: the original rolled a ~0.4%-per-frame chance
 *    continuously while grinding (~3.3s per grind), which works out to roughly
 *    a 55% jam chance per grind — not the requested 1-in-7 (~14.3%). Replaced
 *    with a single roll at the start of each grind, with the jam (if any)
 *    triggering once at a random point partway through.
 *
 * 2. applyRemoteEvent() had no case for 'ORDER_SPAWNED' even though spawnOrder()
 *    emits exactly that event — meaning a remote client would never actually
 *    receive new orders. Added the missing case.
 *
 * 3. MULTIPLAYER AUTHORITY: every client independently runs update() with its
 *    own RNG and its own timers. Left as-is, 3 players' screens would diverge
 *    within seconds (different random jams, different auto-spawned orders).
 *    Fixed with a lightweight authority model rather than a full host/server:
 *      - Each station (grinder/espresso) only self-simulates progress/timeouts
 *        on the client that actually started it locally (tracked via a new
 *        `isLocallyControlled` flag, set on local clicks, left false when
 *        state arrives via applyRemoteEvent). Other clients passively mirror
 *        whatever ticks get relayed to them instead of re-simulating.
 *      - Order spawning is gated behind a single `isOrderAuthority` flag,
 *        which the integration layer sets true for exactly one on-shift
 *        player (deterministically: whoever has been on shift longest) so
 *        orders aren't duplicated across clients.
 *    This means non-authoritative clients won't show perfectly smooth live
 *    progress bars for a station a *different* player is operating — they'll
 *    see it start and then jump to the result. Given the alternative is a
 *    much larger host/server rework, this is a reasonable trade for a casual
 *    3-player minigame; flagging it explicitly rather than hiding it.
 *
 * 4. POS FAULT DOUBLE-COUNTING + FIELD MISMATCH: verifyPosInput() (fired on
 *    every POS button click) compared the modifier selection against
 *    `order.mod`, which doesn't exist — the real field is `order.modifier` —
 *    so every modifier click counted as a mistake even when correct. It also
 *    incremented posFaults per click, on top of the RING IN submit handler's
 *    own (correct) comparison of final submitted values, double-counting.
 *    Fixed: verifyPosInput() now only updates input state; faults are judged
 *    solely by what's actually submitted, not every button clicked en route.
 *
 * 5. SCORE RANGE OVERSHOOT: a fully-loaded order (syrup + modifier) scored
 *    14.4 — the two complexity multipliers (1.5x, 1.2x) stack above the
 *    spec'd 3-12 Clucks range. Added an explicit cap at 12.
 * =====================================================================
 */

// --- SCORING & BALANCING CONFIGURATION ---
export const SCORING_CONFIG = {
  BASE_VALUES: {
    BLACK_COFFEE: 4,
    MILK_DRINK: 8
  },
  COMPLEXITY_MULTIPLIERS: {
    SYRUP: 1.5,
    MODIFIER: 1.2
  },
  PENALTIES: {
    WRONG_POS_BUTTON: 1.5,       // Deducted per incorrect button press
    WRONG_SYRUP: 2.0,            // Deducted for incorrect syrup bottle choice
    MILK_TEMP_MINOR_MISS: 1.0,   // Missed sweet spot, but within acceptable range
    MILK_TEMP_MAJOR_MISS: 3.0,   // Completely under-steamed or severely overheated
    JAM_FUMBLE_PER_SEC: 0.2,     // Penalty per second spent jammed
    TIME_DECAY_START_SEC: 30,    // Time remaining when value begins to decay
    TIME_DECAY_PER_SEC: 0.15     // Penalty per second elapsed past decay start
  },
  MIN_VALUE: 3.0,                // Absolute minimum Clucks awarded for a completed drink
  TIMEOUT_VALUE: 0.0             // Value if order completely expires
};

// Grinder jam: exactly a 1-in-7 chance per grind, rolled once at the start
// (patched — see INTEGRATION PATCH NOTES above).
const GRINDER_JAM_CHANCE = 1 / 7;

export class CoffeeShopMinigame {
  /**
   * @param {HTMLElement} container - DOM element to mount the canvas inside.
   * @param {object} options
   * @param {string} options.localPlayerId - Opaque ID string for the local client.
   * @param {() => number} [options.rng] - Optional seeded random function.
   * @param {boolean} [options.isOrderAuthority] - true for exactly one on-shift
   *   player (the integration layer decides who); only that client's instance
   *   spawns new orders on its timer. Everyone else receives spawned orders via
   *   applyRemoteEvent. Can be changed later via setOrderAuthority().
   */
  constructor(container, options = {}) {
    this.container = container;
    this.localPlayerId = options.localPlayerId || 'player_1';
    this.rng = options.rng || Math.random;
    this.isOrderAuthority = options.isOrderAuthority !== false; // default true for single-player/testing

    // Callbacks
    this.orderCompleteCallback = null;
    this.stateChangeCallback = null;

    // Game Loop State
    this.canvas = null;
    this.ctx = null;
    this.animationFrameId = null;
    this.lastTime = 0;
    this.isRunning = false;

    // Internal Core Engine State
    this.state = {
      orders: [],          // Active order objects
      dripPotCups: 5,      // Standard: 5 cups before rebrew
      isDripPotBrewing: false,
      dripPotBrewTimer: 0,
      activeStation: 'WALKING', // POS, GRINDER, ESPRESSO, DRIP, COUNTER, WALKING
      stations: {
        POS: { activeOrderIndex: -1, input: { type: null, syrup: null, mod: null } },
        GRINDER: {
          progress: 0, isJammed: false, jamClicksNeeded: 0, currentOrderId: null,
          isLocallyControlled: false, willJamThisGrind: false, hasJammedThisGrind: false, jamTriggerProgress: 0
        },
        ESPRESSO: {
          shotProgress: 0, isPulling: false, shotQuality: 'perfect',
          milkTemp: 0, isSteaming: false, targetTempLow: 65, targetTempHigh: 80,
          currentOrderId: null, addedSyrup: null, isLocallyControlled: false
        }
      },
      // Track interactive UI areas
      hitboxes: {}
    };

    // Configuration & Gameplay constants
    this.ORDER_DURATION_MS = 45000;
    this.DRIP_BREW_DURATION_MS = 6000; // 6 seconds rebrew
    this.ORDER_SPAWN_INTERVAL_MS = 12000;
    this.spawnTimer = 0;

    // Layout configuration
    this.width = 900;
    this.height = 600;

    this.initCanvas();
    this.initInputListeners();
  }

  // --- INITIALIZATION ---
  initCanvas() {
    this.canvas = document.createElement('canvas');
    this.canvas.width = this.width;
    this.canvas.height = this.height;
    this.canvas.style.display = 'block';
    this.canvas.style.width = '100%';
    this.canvas.style.height = 'auto';
    this.canvas.style.aspectRatio = `${this.width} / ${this.height}`;
    this.container.appendChild(this.canvas);
    this.ctx = this.canvas.getContext('2d');
    this.setupHitboxes();
  }

  setupHitboxes() {
    // Definitive world space station bounds
    this.state.hitboxes = {
      POS: { x: 50, y: 320, w: 140, h: 160, label: 'POS Register' },
      GRINDER: { x: 230, y: 300, w: 120, h: 180, label: 'Grinder' },
      ESPRESSO: { x: 390, y: 280, w: 220, h: 200, label: 'Espresso Station' },
      DRIP: { x: 650, y: 310, w: 100, h: 170, label: 'Drip Pot' },
      COUNTER: { x: 780, y: 340, w: 100, h: 140, label: 'Hand-off Counter' }
    };
  }

  initInputListeners() {
    this.boundClickHandler = this.handleClick.bind(this);
    this.canvas.addEventListener('click', this.boundClickHandler);
  }

  // --- PUBLIC API METHODS ---
  start() {
    if (this.isRunning) return;
    this.isRunning = true;
    this.lastTime = performance.now();
    this.animationFrameId = requestAnimationFrame((t) => this.loop(t));
  }

  stop() {
    this.isRunning = false;
    if (this.animationFrameId) cancelAnimationFrame(this.animationFrameId);
    if (this.canvas && this.canvas.parentNode) {
      this.canvas.removeEventListener('click', this.boundClickHandler);
      this.canvas.parentNode.removeChild(this.canvas);
    }
  }

  /** Integration layer calls this whenever the deterministic "who spawns orders" pick changes
      (e.g. the previous authority clocks out). Patched in — not in the original delivery. */
  setOrderAuthority(isAuthority) {
    this.isOrderAuthority = isAuthority;
  }

  spawnOrder(orderSpec = null) {
    const spec = orderSpec || this.generateRandomOrderSpec();
    const newOrder = {
      id: spec.id || `order_${Date.now()}_${Math.floor(this.rng() * 1000)}`,
      isBlackCoffee: spec.isBlackCoffee ?? false,
      drinkType: spec.drinkType || 'Latte',
      syrup: spec.syrup || 'None',
      modifier: spec.modifier || 'Standard',
      timeRemaining: this.ORDER_DURATION_MS,
      totalDuration: this.ORDER_DURATION_MS,
      step: 'WAITING_POS', // WAITING_POS -> IN_PROGRESS -> READY_FOR_HANDOUT
      mistakes: { posFaults: 0, wrongSyrup: false, tempDelta: 0, jamTimeMs: 0 },
      posRungIn: false,
      progressFlags: { ground: false, shotPulled: false, shotQuality: 'perfect', milkSteamed: false, milkTemp: 0, syrupAdded: null, dripFilled: false }
    };

    this.state.orders.push(newOrder);
    this.emitStateChange('ORDER_SPAWNED', { order: newOrder });
  }

  onOrderComplete(callback) { this.orderCompleteCallback = callback; }
  onStateChange(callback) { this.stateChangeCallback = callback; }

  getState() {
    return JSON.parse(JSON.stringify({
      orders: this.state.orders,
      dripPotCups: this.state.dripPotCups,
      isDripPotBrewing: this.state.isDripPotBrewing,
      activeStation: this.state.activeStation,
      stations: this.state.stations
    }));
  }

  applyRemoteEvent(event) {
    const { type, data, playerId } = event;
    if (playerId === this.localPlayerId) return; // Prevent echoing self-actions

    switch (type) {
      case 'ORDER_SPAWNED':
        // Patched in — the original engine emitted this but never handled receiving it.
        if (!this.state.orders.find(o => o.id === data.order.id)) {
          this.state.orders.push(data.order);
        }
        break;
      case 'CHANGE_STATION':
        this.state.activeStation = data.station;
        break;
      case 'POS_INPUT':
        this.state.stations.POS.input = data.input;
        this.state.stations.POS.activeOrderIndex = data.activeOrderIndex;
        break;
      case 'POS_SUBMIT':
        if (this.state.orders[data.orderIndex]) {
          this.state.orders[data.orderIndex].posRungIn = true;
          this.state.orders[data.orderIndex].step = 'IN_PROGRESS';
          this.state.orders[data.orderIndex].mistakes.posFaults = data.posFaults;
        }
        this.state.stations.POS.input = { type: null, syrup: null, mod: null };
        break;
      case 'GRINDER_TICK':
        // Mirrored display only — do NOT mark isLocallyControlled here, so this
        // client won't also start independently simulating the grind.
        this.state.stations.GRINDER.progress = data.progress;
        this.state.stations.GRINDER.isJammed = data.isJammed;
        this.state.stations.GRINDER.jamClicksNeeded = data.jamClicksNeeded;
        this.state.stations.GRINDER.currentOrderId = data.currentOrderId;
        break;
      case 'GRINDER_SMACK':
        this.state.stations.GRINDER.jamClicksNeeded = data.jamClicksNeeded;
        this.state.stations.GRINDER.isJammed = data.isJammed;
        break;
      case 'GRINDER_COMPLETE':
        const gOrder = this.state.orders.find(o => o.id === data.orderId);
        if (gOrder) gOrder.progressFlags.ground = true;
        this.state.stations.GRINDER.progress = 0;
        this.state.stations.GRINDER.currentOrderId = null;
        this.state.stations.GRINDER.isLocallyControlled = false;
        break;
      case 'ESPRESSO_PULL_START':
        this.state.stations.ESPRESSO.isPulling = true;
        this.state.stations.ESPRESSO.currentOrderId = data.orderId;
        break;
      case 'ESPRESSO_PULL_STOP':
        this.state.stations.ESPRESSO.isPulling = false;
        this.state.stations.ESPRESSO.shotProgress = 0;
        const pOrder = this.state.orders.find(o => o.id === data.orderId);
        if (pOrder) {
          pOrder.progressFlags.shotPulled = true;
          pOrder.progressFlags.shotQuality = data.quality;
        }
        break;
      case 'ESPRESSO_STEAM_START':
        this.state.stations.ESPRESSO.isSteaming = true;
        this.state.stations.ESPRESSO.targetTempLow = data.low;
        this.state.stations.ESPRESSO.targetTempHigh = data.high;
        break;
      case 'ESPRESSO_STEAM_STOP':
        this.state.stations.ESPRESSO.isSteaming = false;
        const sOrder = this.state.orders.find(o => o.id === data.orderId);
        if (sOrder) {
          sOrder.progressFlags.milkSteamed = true;
          sOrder.progressFlags.milkTemp = data.temp;
          sOrder.mistakes.tempDelta = data.delta;
        }
        this.state.stations.ESPRESSO.milkTemp = 0;
        break;
      case 'ESPRESSO_ADD_SYRUP':
        const syOrder = this.state.orders.find(o => o.id === data.orderId);
        if (syOrder) syOrder.progressFlags.syrupAdded = data.syrup;
        break;
      case 'DRIP_FILL':
        this.state.dripPotCups = data.cups;
        const dOrder = this.state.orders.find(o => o.id === data.orderId);
        if (dOrder) {
          dOrder.progressFlags.dripFilled = true;
          dOrder.step = 'READY_FOR_HANDOUT';
        }
        break;
      case 'DRIP_BREW_START':
        this.state.isDripPotBrewing = true;
        this.state.dripPotBrewTimer = this.DRIP_BREW_DURATION_MS;
        break;
      case 'DRIP_BREW_COMPLETE':
        this.state.isDripPotBrewing = false;
        this.state.dripPotCups = 5;
        break;
      case 'ORDER_HANDOUT':
        this.state.orders = this.state.orders.filter(o => o.id !== data.orderId);
        break;
    }
  }

  // --- INTERNAL ENGINE LOGIC ---
  generateRandomOrderSpec() {
    const isBlackCoffee = this.rng() < 0.05; // 1 in 20 chance
    if (isBlackCoffee) {
      return { isBlackCoffee: true, drinkType: 'Black Coffee', syrup: 'None', modifier: 'Standard' };
    }
    const types = ['Latte', 'Cappuccino', 'Macchiato'];
    const syrups = ['None', 'Vanilla', 'Caramel', 'Hazelnut'];
    const modifiers = ['Standard', 'Extra Hot', 'Iced'];

    return {
      isBlackCoffee: false,
      drinkType: types[Math.floor(this.rng() * types.length)],
      syrup: syrups[Math.floor(this.rng() * syrups.length)],
      modifier: modifiers[Math.floor(this.rng() * modifiers.length)]
    };
  }

  emitStateChange(type, data) {
    if (this.stateChangeCallback) {
      this.stateChangeCallback({ type, data, playerId: this.localPlayerId });
    }
  }

  loop(timestamp) {
    if (!this.isRunning) return;
    const dt = timestamp - this.lastTime;
    this.lastTime = timestamp;

    this.update(dt);
    this.render();

    this.animationFrameId = requestAnimationFrame((t) => this.loop(t));
  }

  update(dt) {
    // Handle background order spawning if queue empty or interval met.
    // Patched: gated behind isOrderAuthority so only one on-shift client spawns —
    // otherwise every client would independently spawn its own divergent orders.
    if (this.isOrderAuthority) {
      this.spawnTimer += dt;
      if (this.state.orders.length === 0 || this.spawnTimer >= this.ORDER_SPAWN_INTERVAL_MS) {
        if (this.state.orders.length < 3) this.spawnOrder();
        this.spawnTimer = 0;
      }
    }

    // Process Drip Pot brewing countdown
    if (this.state.isDripPotBrewing) {
      this.state.dripPotBrewTimer -= dt;
      if (this.state.dripPotBrewTimer <= 0) {
        this.state.isDripPotBrewing = false;
        this.state.dripPotCups = 5;
        this.emitStateChange('DRIP_BREW_COMPLETE', { cups: 5 });
      }
    }

    // Process Active Orders
    for (let i = this.state.orders.length - 1; i >= 0; i--) {
      const order = this.state.orders[i];
      order.timeRemaining -= dt;

      // Accumulate penalty time if order is actively trapped at a jammed grinder
      if (this.state.activeStation === 'GRINDER' && this.state.stations.GRINDER.currentOrderId === order.id && this.state.stations.GRINDER.isJammed) {
        order.mistakes.jamTimeMs += dt;
      }

      // Check automatically for transition to Handout readiness for complex espresso drinks
      if (!order.isBlackCoffee && order.step === 'IN_PROGRESS') {
        if (order.progressFlags.ground && order.progressFlags.shotPulled && order.progressFlags.milkSteamed) {
          order.step = 'READY_FOR_HANDOUT';
        }
      }

      // Handle raw expiration context
      if (order.timeRemaining <= 0) {
        order.timeRemaining = 0;
        // Keep order in frame for explicit delivery checkout closure per spec requirement
      }
    }

    // Process Active Automation Progress States.
    // Patched: gated behind isLocallyControlled — only the client that actually
    // started this grind runs its progress/jam simulation; everyone else just
    // mirrors GRINDER_TICK/GRINDER_COMPLETE events via applyRemoteEvent.
    if (this.state.stations.GRINDER.currentOrderId && !this.state.stations.GRINDER.isJammed && this.state.stations.GRINDER.isLocallyControlled) {
      const g = this.state.stations.GRINDER;
      g.progress += dt * 0.03; // ~3.3 seconds to complete standard grind

      if (g.willJamThisGrind && !g.hasJammedThisGrind && g.progress >= g.jamTriggerProgress) {
        g.hasJammedThisGrind = true;
        g.isJammed = true;
        g.jamClicksNeeded = Math.floor(this.rng() * 3) + 1;
        this.emitStateChange('GRINDER_TICK', g);
      } else if (g.progress >= 100) {
        const orderId = g.currentOrderId;
        const ord = this.state.orders.find(o => o.id === orderId);
        if (ord) ord.progressFlags.ground = true;
        this.emitStateChange('GRINDER_COMPLETE', { orderId });
        g.progress = 0;
        g.currentOrderId = null;
        g.isLocallyControlled = false;
      }
    }

    if (this.state.stations.ESPRESSO.isPulling && this.state.stations.ESPRESSO.isLocallyControlled) {
      const esp = this.state.stations.ESPRESSO;
      esp.shotProgress += dt * 0.04;
      if (esp.shotProgress >= 140) { // Over-extracted automatically if forgotten
        esp.isPulling = false;
        esp.shotProgress = 0;
        const ord = this.state.orders.find(o => o.id === esp.currentOrderId);
        if (ord) {
          ord.progressFlags.shotPulled = true;
          ord.progressFlags.shotQuality = 'burnt';
        }
        this.emitStateChange('ESPRESSO_PULL_STOP', { orderId: esp.currentOrderId, quality: 'burnt' });
      }
    }

    if (this.state.stations.ESPRESSO.isSteaming && this.state.stations.ESPRESSO.isLocallyControlled) {
      const esp = this.state.stations.ESPRESSO;
      esp.milkTemp += dt * 0.05; // Quick linear rise scaling
      if (esp.milkTemp >= 120) { // Complete boiling disaster point
        esp.isSteaming = false;
        const ord = this.state.orders.find(o => o.id === esp.currentOrderId);
        if (ord) {
          ord.progressFlags.milkSteamed = true;
          ord.progressFlags.milkTemp = esp.milkTemp;
          ord.mistakes.tempDelta = Math.abs(esp.milkTemp - (esp.targetTempLow + 7.5));
        }
        this.emitStateChange('ESPRESSO_STEAM_STOP', { orderId: esp.currentOrderId, temp: esp.milkTemp, delta: esp.milkTemp });
        esp.milkTemp = 0;
      }
    }
  }

  // --- INTERACTION / INPUT ROUTING ---
  handleClick(e) {
    const rect = this.canvas.getBoundingClientRect();
    const scaleX = this.width / rect.width;
    const scaleY = this.height / rect.height;
    const x = (e.clientX - rect.left) * scaleX;
    const y = (e.clientY - rect.top) * scaleY;

    // Overlay Interception Layer UI handling logic blocks primary traversal
    if (this.state.activeStation !== 'WALKING') {
      if (this.handleOverlayClicks(x, y)) return;
    }

    // World Map Layout Traversal Intersection checks
    for (const [stationKey, box] of Object.entries(this.state.hitboxes)) {
      if (x >= box.x && x <= box.x + box.w && y >= box.y && y <= box.y + box.h) {
        this.state.activeStation = stationKey;
        this.emitStateChange('CHANGE_STATION', { station: stationKey });
        this.syncStationContexts();
        return;
      }
    }
  }

  syncStationContexts() {
    // Dynamically lock sub-operational components to matching order heads
    if (this.state.activeStation === 'POS' && this.state.stations.POS.activeOrderIndex === -1) {
      this.state.stations.POS.activeOrderIndex = this.state.orders.findIndex(o => o.step === 'WAITING_POS');
    }
    const currentActiveJob = this.state.orders.find(o => o.step === 'IN_PROGRESS');
    if (currentActiveJob) {
      if (!currentActiveJob.isBlackCoffee) {
        if (!currentActiveJob.progressFlags.ground && !this.state.stations.GRINDER.currentOrderId) {
          this.state.stations.GRINDER.currentOrderId = currentActiveJob.id;
        }
        if (currentActiveJob.progressFlags.ground && !this.state.stations.ESPRESSO.currentOrderId) {
          this.state.stations.ESPRESSO.currentOrderId = currentActiveJob.id;
        }
      }
    }
  }

  handleOverlayClicks(x, y) {
    // Global Close Button intercept for overlays
    if (x >= 830 && x <= 870 && y >= 30 && y <= 70) {
      this.state.activeStation = 'WALKING';
      this.emitStateChange('CHANGE_STATION', { station: 'WALKING' });
      return true;
    }

    const currentOrder = this.state.orders.find(o => o.step === 'IN_PROGRESS');

    if (this.state.activeStation === 'POS') {
      const idx = this.state.stations.POS.activeOrderIndex;
      const targetOrder = this.state.orders[idx];
      if (!targetOrder) return false;

      // POS Button Matrix Click Detection Coordinate Triggers
      if (y >= 260 && y <= 300) { // Drink type rows
        if (x >= 150 && x <= 270) this.verifyPosInput('type', 'Latte', targetOrder);
        if (x >= 290 && x <= 410) this.verifyPosInput('type', 'Cappuccino', targetOrder);
        if (x >= 430 && x <= 550) this.verifyPosInput('type', 'Macchiato', targetOrder);
      } else if (y >= 350 && y <= 390) { // Syrups
        if (x >= 150 && x <= 250) this.verifyPosInput('syrup', 'None', targetOrder);
        if (x >= 270 && x <= 370) this.verifyPosInput('syrup', 'Vanilla', targetOrder);
        if (x >= 390 && x <= 490) this.verifyPosInput('syrup', 'Caramel', targetOrder);
        if (x >= 510 && x <= 610) this.verifyPosInput('syrup', 'Hazelnut', targetOrder);
      } else if (y >= 440 && y <= 480) { // Modifiers
        if (x >= 150 && x <= 270) this.verifyPosInput('mod', 'Standard', targetOrder);
        if (x >= 290 && x <= 410) this.verifyPosInput('mod', 'Extra Hot', targetOrder);
        if (x >= 430 && x <= 550) this.verifyPosInput('mod', 'Iced', targetOrder);
      } else if (x >= 650 && x <= 780 && y >= 430 && y <= 480) {
        // Submit Button Rung In Match Trigger Evaluation
        let faults = targetOrder.mistakes.posFaults;
        const inp = this.state.stations.POS.input;
        if (inp.type !== targetOrder.drinkType) faults++;
        if (inp.syrup !== targetOrder.syrup) faults++;
        if (inp.mod !== targetOrder.modifier) faults++;

        targetOrder.posRungIn = true;
        targetOrder.step = 'IN_PROGRESS';
        targetOrder.mistakes.posFaults = faults;

        this.emitStateChange('POS_SUBMIT', { orderIndex: idx, posFaults: faults });
        this.state.stations.POS.input = { type: null, syrup: null, mod: null };
        this.state.stations.POS.activeOrderIndex = -1;
        this.state.activeStation = 'WALKING';
      }
      return true;
    }

    if (this.state.activeStation === 'GRINDER') {
      const g = this.state.stations.GRINDER;
      if (g.isJammed) {
        if (x >= 350 && x <= 550 && y >= 320 && y <= 380) {
          g.jamClicksNeeded--;
          if (g.jamClicksNeeded <= 0) g.isJammed = false;
          this.emitStateChange('GRINDER_SMACK', { jamClicksNeeded: g.jamClicksNeeded, isJammed: g.isJammed });
        }
      } else if (!g.currentOrderId && currentOrder && !currentOrder.isBlackCoffee && !currentOrder.progressFlags.ground) {
        if (x >= 380 && x <= 520 && y >= 260 && y <= 310) {
          g.currentOrderId = currentOrder.id;
          g.progress = 1;
          g.isLocallyControlled = true;
          g.hasJammedThisGrind = false;
          g.willJamThisGrind = this.rng() < GRINDER_JAM_CHANCE;
          g.jamTriggerProgress = g.willJamThisGrind ? (30 + this.rng() * 40) : 0;
          this.emitStateChange('GRINDER_TICK', g);
        }
      }
      return true;
    }

    if (this.state.activeStation === 'ESPRESSO') {
      const esp = this.state.stations.ESPRESSO;
      if (!currentOrder || currentOrder.isBlackCoffee) return true;

      // Click Trigger: Pull Shot Toggle button
      if (x >= 150 && x <= 280 && y >= 200 && y <= 250) {
        if (!esp.isPulling && !currentOrder.progressFlags.shotPulled) {
          esp.isPulling = true;
          esp.isLocallyControlled = true;
          esp.currentOrderId = currentOrder.id;
          this.emitStateChange('ESPRESSO_PULL_START', { orderId: currentOrder.id });
        } else if (esp.isPulling) {
          esp.isPulling = false;
          let qual = 'perfect';
          if (esp.shotProgress < 40 || esp.shotProgress > 110) qual = 'watery';
          if (esp.shotProgress > 85 && esp.shotProgress <= 110) qual = 'good';
          if (esp.shotProgress >= 60 && esp.shotProgress <= 85) qual = 'perfect';

          currentOrder.progressFlags.shotPulled = true;
          currentOrder.progressFlags.shotQuality = qual;
          this.emitStateChange('ESPRESSO_PULL_STOP', { orderId: currentOrder.id, quality: qual });
          esp.shotProgress = 0;
        }
      }

      // Click Trigger: Steam Milk Action Window
      if (x >= 150 && x <= 280 && y >= 400 && y <= 450) {
        if (!esp.isSteaming && !currentOrder.progressFlags.milkSteamed) {
          esp.isSteaming = true;
          esp.isLocallyControlled = true;
          esp.currentOrderId = currentOrder.id;
          esp.milkTemp = 10;
          // Dynamically randomize the target hot zone per specific order run configuration
          esp.targetTempLow = 55 + Math.floor(this.rng() * 20);
          esp.targetTempHigh = esp.targetTempLow + 18;
          this.emitStateChange('ESPRESSO_STEAM_START', { low: esp.targetTempLow, high: esp.targetTempHigh });
        } else if (esp.isSteaming) {
          esp.isSteaming = false;
          let delta = 0;
          if (esp.milkTemp < esp.targetTempLow) delta = esp.targetTempLow - esp.milkTemp;
          if (esp.milkTemp > esp.targetTempHigh) delta = esp.milkTemp - esp.targetTempHigh;

          currentOrder.progressFlags.milkSteamed = true;
          currentOrder.progressFlags.milkTemp = esp.milkTemp;
          currentOrder.mistakes.tempDelta = delta;

          this.emitStateChange('ESPRESSO_STEAM_STOP', { orderId: currentOrder.id, temp: esp.milkTemp, delta });
          esp.milkTemp = 0;
        }
      }

      // Click Trigger Array: Flavored Syrup Pump Station Rack Selector
      if (y >= 280 && y <= 350) {
        let pickedSyrup = null;
        if (x >= 630 && x <= 670) pickedSyrup = 'Vanilla';
        if (x >= 690 && x <= 730) pickedSyrup = 'Caramel';
        if (x >= 750 && x <= 790) pickedSyrup = 'Hazelnut';

        if (pickedSyrup) {
          currentOrder.progressFlags.syrupAdded = pickedSyrup;
          if (currentOrder.syrup !== pickedSyrup) {
            currentOrder.mistakes.wrongSyrup = true;
          }
          this.emitStateChange('ESPRESSO_ADD_SYRUP', { orderId: currentOrder.id, syrup: pickedSyrup });
        }
      }
      return true;
    }

    if (this.state.activeStation === 'DRIP') {
      if (this.state.isDripPotBrewing) return true;
      // Rebrew Trigger Click Intersection check
      if (x >= 480 && x <= 620 && y >= 360 && y <= 410) {
        this.state.isDripPotBrewing = true;
        this.state.dripPotBrewTimer = this.DRIP_BREW_DURATION_MS;
        this.emitStateChange('DRIP_BREW_START', {});
        return true;
      }
      // Cup Dispense fill collection trigger
      if (currentOrder && currentOrder.isBlackCoffee && !currentOrder.progressFlags.dripFilled && this.state.dripPotCups > 0) {
        if (x >= 320 && x <= 440 && y >= 250 && y <= 300) {
          this.state.dripPotCups--;
          currentOrder.progressFlags.dripFilled = true;
          currentOrder.step = 'READY_FOR_HANDOUT';
          this.emitStateChange('DRIP_FILL', { orderId: currentOrder.id, cups: this.state.dripPotCups });
        }
      }
      return true;
    }

    if (this.state.activeStation === 'COUNTER') {
      // Find orders matching complete delivery state profile conditions ready for clearance
      const readyOrderIndex = this.state.orders.findIndex(o => o.step === 'READY_FOR_HANDOUT' || o.timeRemaining <= 0);
      if (readyOrderIndex !== -1) {
        const order = this.state.orders[readyOrderIndex];
        if (x >= 350 && x <= 550 && y >= 420 && y <= 480) {
          const finalScore = this.calculateOrderScore(order);
          if (this.orderCompleteCallback) {
            this.orderCompleteCallback({
              orderId: order.id,
              value: finalScore,
              complexity: order.isBlackCoffee ? 'Low' : 'High',
              mistakes: order.mistakes,
              wasBlackCoffee: order.isBlackCoffee,
              tookMs: order.totalDuration - order.timeRemaining
            });
          }
          this.emitStateChange('ORDER_HANDOUT', { orderId: order.id });
          this.state.orders.splice(readyOrderIndex, 1);
          this.state.activeStation = 'WALKING';
        }
      }
      return true;
    }

    return false;
  }

  verifyPosInput(field, value, order) {
    // Patched: this used to also increment order.mistakes.posFaults here, per click —
    // but (a) it compared against `order.mod`, which doesn't exist (the real field is
    // `order.modifier`), so every modifier click counted as wrong even when correct, and
    // (b) the RING IN submit handler below does its own correct comparison against the
    // final submitted values and adds its own faults on top, double-counting on top of
    // that bug. Faults should only be judged by what's actually submitted, not every
    // button clicked while deciding — so this now only updates the input state.
    this.state.stations.POS.input[field] = value;
    this.emitStateChange('POS_INPUT', { 
      input: this.state.stations.POS.input, 
      activeOrderIndex: this.state.stations.POS.activeOrderIndex 
    });
  }

  // --- SCORE CALCULATION ENGINE ---
  calculateOrderScore(order) {
    if (order.timeRemaining <= 0) return SCORING_CONFIG.TIMEOUT_VALUE;

    const cfg = SCORING_CONFIG;
    let score = order.isBlackCoffee ? cfg.BASE_VALUES.BLACK_COFFEE : cfg.BASE_VALUES.MILK_DRINK;

    // Apply Complexity upgrades
    if (order.syrup !== 'None') score *= cfg.COMPLEXITY_MULTIPLIERS.SYRUP;
    if (order.modifier !== 'Standard') score *= cfg.COMPLEXITY_MULTIPLIERS.MODIFIER;

    // Process Explicit structural workflow penalty deductions
    score -= (order.mistakes.posFaults * cfg.PENALTIES.WRONG_POS_BUTTON);
    if (order.mistakes.wrongSyrup) score -= cfg.PENALTIES.WRONG_SYRUP;

    // Temperature extraction evaluation variance penalties
    if (!order.isBlackCoffee) {
      const d = order.mistakes.tempDelta;
      if (d > 0 && d <= 10) score -= cfg.PENALTIES.MILK_TEMP_MINOR_MISS;
      if (d > 10) score -= cfg.PENALTIES.MILK_TEMP_MAJOR_MISS;

      // Quality of espresso pull profile evaluation bounds
      if (order.progressFlags.shotQuality === 'watery') score -= 1.5;
      if (order.progressFlags.shotQuality === 'burnt') score -= 3.0;
    }

    // Jam delay scaling metrics
    const jamSec = order.mistakes.jamTimeMs / 1000;
    score -= (jamSec * cfg.PENALTIES.JAM_FUMBLE_PER_SEC);

    // Dynamic Time-decay calculation
    const timeSec = order.timeRemaining / 1000;
    const elapsedSec = (order.totalDuration / 1000) - timeSec;
    if (elapsedSec > cfg.PENALTIES.TIME_DECAY_START_SEC) {
      const decayOver = elapsedSec - cfg.PENALTIES.TIME_DECAY_START_SEC;
      score -= (decayOver * cfg.PENALTIES.TIME_DECAY_PER_SEC);
    }

    // Final clean precision constraints clamp returns
    // Patched: also cap at 12 — the syrup (1.5x) and modifier (1.2x) multipliers can
    // stack to 14.4 on a fully-loaded order otherwise, above the spec'd 3-12 range.
    return parseFloat(Math.min(12, Math.max(cfg.MIN_VALUE, score)).toFixed(1));
  }

  // --- RENDERING PIPELINE (CANVAS 2D) ---
  render() {
    this.ctx.clearRect(0, 0, this.width, this.height);

    if (this.state.activeStation === 'WALKING') {
      this.renderMainShopFloor();
    } else {
      this.renderStationOverlay();
    }
  }

  renderMainShopFloor() {
    // 1. Background Wall color spaces
    this.ctx.fillStyle = '#F4E9D8';
    this.ctx.fillRect(0, 0, this.width, this.height);

    // Floor space divider trim
    this.ctx.fillStyle = '#E5D3B3';
    this.ctx.fillRect(0, 480, this.width, 120);
    this.ctx.fillStyle = '#1F2A44';
    this.ctx.fillRect(0, 476, this.width, 4);

    // 2. Render Order Ticket Rail System HUD Header
    this.renderTicketRail();

    // 3. Render Stations via declarative loops using generic shape assets
    for (const [key, box] of Object.entries(this.state.hitboxes)) {
      this.ctx.save();
      
      // Counter foundation connection setups
      this.ctx.fillStyle = '#8B5A2B';
      this.ctx.lineWidth = 4;
      this.ctx.strokeStyle = '#1F2A44';

      this.ctx.beginPath();
      this.ctx.roundRect(box.x, box.y, box.w, box.h, 12);
      this.ctx.fill();
      this.ctx.stroke();

      // Top trim cap board accent line
      this.ctx.fillStyle = '#6B4222';
      this.ctx.fillRect(box.x - 4, box.y, box.w + 8, 15);
      this.ctx.strokeRect(box.x - 4, box.y, box.w + 8, 15);

      // Station Specific Hardware Silhouette Icons representation
      this.ctx.fillStyle = '#A0AAB5';
      if (key === 'POS') {
        this.ctx.fillRect(box.x + 35, box.y - 30, 70, 30);
        this.ctx.strokeRect(box.x + 35, box.y - 30, 70, 30);
      } else if (key === 'GRINDER') {
        this.ctx.fillStyle = '#4A5568';
        this.ctx.fillRect(box.x + 40, box.y - 50, 40, 50);
        this.ctx.strokeRect(box.x + 40, box.y - 50, 40, 50);
        if (this.state.stations.GRINDER.isJammed) {
          this.ctx.fillStyle = '#E8433D';
          this.ctx.font = 'bold 14px sans-serif';
          this.ctx.fillText('⚠️ JAM', box.x + 35, box.y - 65);
        }
      } else if (key === 'ESPRESSO') {
        this.ctx.fillRect(box.x + 40, box.y - 60, 140, 60);
        this.ctx.strokeRect(box.x + 40, box.y - 60, 140, 60);
      } else if (key === 'DRIP') {
        this.ctx.fillStyle = '#2D3748';
        this.ctx.fillRect(box.x + 25, box.y - 45, 50, 45);
        this.ctx.strokeRect(box.x + 25, box.y - 45, 50, 45);
        this.ctx.fillStyle = '#FFF';
        this.ctx.font = '12px sans-serif';
        this.ctx.fillText(`☕ ${this.state.dripPotCups}/5`, box.x + 30, box.y - 55);
      }

      // Metadata Label formatting
      this.ctx.fillStyle = '#1F2A44';
      this.ctx.font = 'bold 14px sans-serif';
      this.ctx.textAlign = 'center';
      this.ctx.fillText(box.label, box.x + box.w / 2, box.y + box.h / 2);
      
      this.ctx.restore();
    }
  }

  renderTicketRail() {
    this.ctx.fillStyle = '#2C3E50';
    this.ctx.fillRect(0, 0, this.width, 35);
    
    this.state.orders.forEach((order, index) => {
      const tx = 40 + (index * 260);
      const ty = 8;
      const tw = 240;
      const th = 85;

      // Card Base
      this.ctx.fillStyle = order.timeRemaining <= 0 ? '#FDEDEC' : '#FFFFFF';
      this.ctx.lineWidth = 3;
      this.ctx.strokeStyle = order.step === 'READY_FOR_HANDOUT' ? '#2ECC71' : '#1F2A44';
      
      this.ctx.beginPath();
      this.ctx.roundRect(tx, ty, tw, th, 8);
      this.ctx.fill();
      this.ctx.stroke();

      // Top state flags banner accents
      this.ctx.fillStyle = order.isBlackCoffee ? '#795548' : '#3498DB';
      this.ctx.fillRect(tx + 1, ty + 1, tw - 2, 6);

      // Order String content injection layout lines
      this.ctx.fillStyle = '#1F2A44';
      this.ctx.textAlign = 'left';
      this.ctx.font = 'bold 13px sans-serif';
      this.ctx.fillText(`${order.drinkType} (${order.syrup})`, tx + 12, ty + 28);
      this.ctx.font = '11px sans-serif';
      this.ctx.fillText(`Mod: ${order.modifier}`, tx + 12, ty + 46);

      // System Progress Ring execution tracking strings badges
      let progressStr = order.step;
      if (order.step === 'IN_PROGRESS') {
        if (order.isBlackCoffee) progressStr = 'Need Drip Pour';
        else progressStr = `G:${order.progressFlags.ground?'Y':'N'} P:${order.progressFlags.shotPulled?'Y':'N'} S:${order.progressFlags.milkSteamed?'Y':'N'}`;
      }
      this.ctx.fillStyle = '#7F8C8D';
      this.ctx.fillText(progressStr, tx + 12, ty + 64);

      // Remaining Radial/Horizontal Bar Timer indicators
      const pct = order.timeRemaining / order.totalDuration;
      this.ctx.fillStyle = pct < 0.3 ? '#E8433D' : '#FFD23F';
      this.ctx.fillRect(tx + 12, ty + 72, (tw - 24) * pct, 6);
      this.ctx.strokeRect(tx + 12, ty + 72, tw - 24, 6);
    });
  }

  renderStationOverlay() {
    // Fill deep high-contrast backdrop overlay blur space mask sheet
    this.ctx.fillStyle = 'rgba(31, 42, 68, 0.85)';
    this.ctx.fillRect(0, 0, this.width, this.height);

    // Inner dialog board shell interface panel
    this.ctx.fillStyle = '#F4E9D8';
    this.ctx.strokeStyle = '#FFFFFF';
    this.ctx.lineWidth = 6;
    this.ctx.beginPath();
    this.ctx.roundRect(50, 50, 800, 500, 24);
    this.ctx.fill();
    this.ctx.stroke();

    // Universal Close Target Window Icon
    this.ctx.fillStyle = '#E8433D';
    this.ctx.strokeStyle = '#1F2A44';
    this.ctx.lineWidth = 4;
    this.ctx.beginPath();
    this.ctx.roundRect(830, 30, 40, 40, 10);
    this.ctx.fill();
    this.ctx.stroke();
    this.ctx.fillStyle = '#FFF';
    this.ctx.font = 'bold 20px sans-serif';
    this.ctx.textAlign = 'center';
    this.ctx.fillText('X', 850, 58);

    // Direct dynamic subclass pipeline draw calls
    this.ctx.fillStyle = '#1F2A44';
    this.ctx.textAlign = 'left';
    this.ctx.font = 'bold 24px sans-serif';
    this.ctx.fillText(`STATION: ${this.state.activeStation}`, 90, 95);

    switch (this.state.activeStation) {
      case 'POS': this.drawPosOverlay(); break;
      case 'GRINDER': this.drawGrinderOverlay(); break;
      case 'ESPRESSO': this.drawEspressoOverlay(); break;
      case 'DRIP': this.drawDripOverlay(); break;
      case 'COUNTER': this.drawCounterOverlay(); break;
    }
  }

  // --- SUB-STATION INTERFACE GRAPHICS BUILDERS ---
  drawPosOverlay() {
    const idx = this.state.stations.POS.activeOrderIndex;
    const order = this.state.orders[idx];

    if (!order) {
      this.ctx.fillText('No orders waiting to be rung in at POS!', 150, 240);
      return;
    }

    this.ctx.font = '16px sans-serif';
    this.ctx.fillText(`Target Ticket Specifications:`, 150, 150);
    this.ctx.fillStyle = '#E8433D';
    this.ctx.font = 'bold 18px sans-serif';
    this.ctx.fillText(`Drink: ${order.drinkType}  |  Syrup: ${order.syrup}  |  Modifier: ${order.modifier}`, 150, 180);

    const input = this.state.stations.POS.input;
    this.ctx.fillStyle = '#1F2A44';
    this.ctx.font = '14px sans-serif';

    // Matrix Button Rows
    this.ctx.fillText('1. DRINK TYPE', 150, 240);
    this.drawUiButton('Latte', 150, 260, 120, 40, input.type === 'Latte');
    this.drawUiButton('Cappuccino', 290, 260, 120, 40, input.type === 'Cappuccino');
    this.drawUiButton('Macchiato', 430, 260, 120, 40, input.type === 'Macchiato');

    this.ctx.fillStyle = '#1F2A44';
    this.ctx.fillText('2. SYRUP PUMP', 150, 330);
    this.drawUiButton('None', 150, 350, 100, 40, input.syrup === 'None');
    this.drawUiButton('Vanilla', 270, 350, 100, 40, input.syrup === 'Vanilla');
    this.drawUiButton('Caramel', 390, 350, 100, 40, input.syrup === 'Caramel');
    this.drawUiButton('Hazelnut', 510, 350, 100, 40, input.syrup === 'Hazelnut');

    this.ctx.fillStyle = '#1F2A44';
    this.ctx.fillText('3. MODIFIER OPTION', 150, 420);
    this.drawUiButton('Standard', 150, 440, 120, 40, input.mod === 'Standard');
    this.drawUiButton('Extra Hot', 290, 440, 120, 40, input.mod === 'Extra Hot');
    this.drawUiButton('Iced', 430, 440, 120, 40, input.mod === 'Iced');

    // Submission Core Panel
    this.drawUiButton('RING IN ✅', 650, 430, 130, 50, false, '#FFD23F');
  }

  drawGrinderOverlay() {
    const g = this.state.stations.GRINDER;

    if (g.isJammed) {
      this.ctx.fillStyle = '#E8433D';
      this.ctx.font = 'bold 28px sans-serif';
      this.ctx.fillText('🚨 GRINDER BLADE JAMMED!', 280, 220);
      this.drawUiButton(`Smack Grinder 🔨 (${g.jamClicksNeeded})`, 350, 320, 200, 60, false, '#FFD23F');
      return;
    }

    if (g.currentOrderId) {
      this.ctx.fillText('Grinding espresso beans...', 320, 220);
      // Progress Frame container
      this.ctx.strokeRect(250, 280, 400, 30);
      this.ctx.fillStyle = '#6B4222';
      this.ctx.fillRect(252, 282, (396) * (g.progress / 100), 26);
    } else {
      this.ctx.fillText('Grinder is vacant and ready.', 300, 220);
      this.drawUiButton('Start Grinding', 380, 260, 140, 50, false, '#2ECC71');
    }
  }

  drawEspressoOverlay() {
    const esp = this.state.stations.ESPRESSO;
    const currentOrder = this.state.orders.find(o => o.step === 'IN_PROGRESS');

    if (!currentOrder || currentOrder.isBlackCoffee) {
      this.ctx.fillText('No valid active espresso order in progress.', 150, 200);
      return;
    }

    // Shot Pulling Module Section
    this.ctx.strokeRect(150, 130, 200, 25);
    if (esp.isPulling) {
      this.ctx.fillStyle = '#6B4222';
      this.ctx.fillRect(152, 132, Math.min(196, esp.shotProgress * 1.4), 21);
      // Sweets zone target lines visualization elements
      this.ctx.fillStyle = 'rgba(46, 204, 113, 0.4)';
      this.ctx.fillRect(150 + 60, 130, 35, 25);
    }
    this.drawUiButton(esp.isPulling ? 'STOP SHOT' : 'PULL SHOT', 150, 200, 130, 50, false, esp.isPulling ? '#E8433D':'#2ECC71');
    this.ctx.fillStyle = '#1F2A44';
    this.ctx.font = '12px sans-serif';
    this.ctx.fillText(`Shot status: ${currentOrder.progressFlags.shotPulled ? 'Done (' + currentOrder.progressFlags.shotQuality + ')' : 'Empty'}`, 150, 180);

    // Steaming Milk Module Section
    this.ctx.font = 'bold 14px sans-serif';
    this.ctx.fillText('Milk Thermometer Wand', 150, 320);
    this.ctx.strokeRect(150, 340, 250, 30);
    
    // Draw target randomized zone band
    this.ctx.fillStyle = '#2ECC71';
    this.ctx.fillRect(150 + esp.targetTempLow, 341, (esp.targetTempHigh - esp.targetTempLow), 28);

    if (esp.isSteaming) {
      this.ctx.fillStyle = '#E8433D';
      this.ctx.fillRect(150 + esp.milkTemp, 335, 4, 40);
    }
    this.drawUiButton(esp.isSteaming ? 'STOP STEAM' : 'STEAM MILK', 150, 400, 130, 50, false, esp.isSteaming ? '#E8433D':'#2ECC71');

    // Syrup Rack Selector pump arrays sidebar mechanics layouts
    this.ctx.fillStyle = '#1F2A44';
    this.ctx.font = 'bold 16px sans-serif';
    this.ctx.fillText('Syrup Pumps Rack', 620, 150);
    
    this.drawUiButton('VNL', 630, 280, 40, 70, currentOrder.progressFlags.syrupAdded === 'Vanilla', '#F4D03F');
    this.drawUiButton('CRM', 690, 280, 40, 70, currentOrder.progressFlags.syrupAdded === 'Caramel', '#D35400');
    this.drawUiButton('HZL', 750, 280, 40, 70, currentOrder.progressFlags.syrupAdded === 'Hazelnut', '#935116');
  }

  drawDripOverlay() {
    this.ctx.fillText(`Drip Pot Level: ${this.state.dripPotCups} / 5 Cups Remaining`, 150, 180);

    if (this.state.isDripPotBrewing) {
      this.ctx.fillStyle = '#D35400';
      this.ctx.fillText(`BREWING FRESH COFFEE - ${(this.state.dripPotBrewTimer/1000).toFixed(1)}s`, 150, 240);
      return;
    }

    const currentOrder = this.state.orders.find(o => o.step === 'IN_PROGRESS');
    if (currentOrder && currentOrder.isBlackCoffee && !currentOrder.progressFlags.dripFilled) {
      this.drawUiButton('Pour Cup from Drip Pot', 320, 250, 220, 50, false, '#2ECC71');
    }

    this.drawUiButton('Rebrew Entire Pot 🔄', 480, 360, 160, 50, false, '#FFD23F');
  }

  drawCounterOverlay() {
    const readyOrder = this.state.orders.find(o => o.step === 'READY_FOR_HANDOUT' || o.timeRemaining <= 0);

    if (!readyOrder) {
      this.ctx.fillText('No drinks ready for delivery onto the serving table counter tray.', 150, 220);
      return;
    }

    this.ctx.fillText(`Serving Up Completed Ticket Order:`, 150, 180);
    this.ctx.fillStyle = '#2ECC71';
    this.ctx.font = 'bold 22px sans-serif';
    this.ctx.fillText(`${readyOrder.drinkType} [${readyOrder.modifier}]`, 150, 220);

    this.ctx.fillStyle = '#1F2A44';
    this.ctx.font = '14px sans-serif';
    if (readyOrder.timeRemaining <= 0) {
      this.ctx.fillStyle = '#E8433D';
      this.ctx.fillText('⚠️ Order Expired! Value will drop to 0 Clucks.', 150, 280);
    } else {
      this.ctx.fillText('Execution parameters pristine. Fast delivery secures higher multiplier rewards.', 150, 280);
    }

    this.drawUiButton('HAND OUT DRINK ☕', 350, 420, 200, 60, false, '#FFD23F');
  }

  drawUiButton(text, x, y, w, h, isSelected = false, customColor = null) {
    this.ctx.save();
    this.ctx.lineWidth = 4;
    this.ctx.strokeStyle = '#1F2A44';
    
    if (isSelected) {
      this.ctx.fillStyle = '#34495E';
    } else {
      this.ctx.fillStyle = customColor || '#FFFFFF';
    }

    this.ctx.beginPath();
    this.ctx.roundRect(x, y, w, h, 10);
    this.ctx.fill();
    this.ctx.stroke();

    this.ctx.fillStyle = isSelected ? '#FFFFFF' : '#1F2A44';
    this.ctx.font = 'bold 13px sans-serif';
    this.ctx.textAlign = 'center';
    this.ctx.textBaseline = 'middle';
    this.ctx.fillText(text, x + w / 2, y + h / 2);
    this.ctx.restore();
  }
}
